// src/components/LandList.js
import React from 'react';

const LandList = ({ records }) => {
  return (
    <div>
      {records.map((record, index) => (
        <div key={index}>
          <p><strong>{record.land_name}</strong></p>
          <p>Survey Number: {record.survey_number}</p>
        </div>
      ))}
    </div>
  );
}

export default LandList;
